};

export const UNIT_LABELS = {
  temperature: { C: '°C', F: '°F' },
  windSpeed: { metric: 'm/s', imperial: 'mph' },
  humidity: '%',
};

export const FORECAST_DAYS_LIMIT = 5;

export const formatTemperature = (temp: number, unit: string): string => {
  const label = UNIT_LABELS.temperature[unit as keyof typeof UNIT_LABELS.temperature] || unit;
  return `${temp}${label}`;
};

export const formatHumidity = (humidity: number): string => {
  return `${humidity}${UNIT_LABELS.humidity}`;
};

export const formatWindSpeed = (speed: number, unit: string): string => {
  const label = UNIT_LABELS.windSpeed[unit as keyof typeof UNIT_LABELS.windSpeed] || unit;
  return `${speed} ${label}`;
};


