export const MAX_STEPS = 3;

export const WIZARD_STEPS = [
  { id: 0, title: 'Profile Information', description: 'Set up your name and contact details.' },
  { id: 1, title: 'Preferences', description: 'Define your role and application settings.' },
  { id: 2, title: 'Review', description: 'Confirm your details before finishing.' },
];

export const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export const INITIAL_PROFILE_DATA: ProfileData = {
  name: '',
  email: '',
  avatar: '',
  role: '',
  emailNotifications: false,
  theme: 'light',
};

export const UI_LABELS = {
  next: 'Next',
  back: 'Back',
