};

// --- hooks.ts ---
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
import { useState, useMemo, useCallback } from 'react';

export function useComponent(props: OnboardingWizardProps): WizardHookReturn {
  const [currentStep, setCurrentStep] = useState(1);

  const [profileData, setProfileData] = useState<ProfileData>(() => ({
    name: props.initialProfile?.name ?? "",
    email: props.initialProfile?.email ?? "",
    avatar: props.initialProfile?.avatar ?? props.avatarOptions[0] ?? "",
    role: props.initialProfile?.role ?? props.roleOptions[0] ?? "",
    emailNotifications: props.initialProfile?.emailNotifications ?? false,
    theme: props.initialProfile?.theme ?? "light",
  }));

  const isNextDisabled = useMemo(() => {
    if (currentStep === 1) {
      const emailRegex = /^\S+@\S+\.\S+$/;
      return !profileData.name || !profileData.email || !emailRegex.test(profileData.email);
    }
    return false;
  }, [currentStep, profileData.name, profileData.email]);

  const handleNext = useCallback(() => {
    if (currentStep < 3) {
      setCurrentStep((prev) => prev + 1);
    }
  }, [currentStep]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep((prev) => prev - 1);
    }
  }, [currentStep]);

  const updateField = useCallback(<K extends keyof ProfileData>(field: K, value: ProfileData[K]) => {
    setProfileData((prev) => ({
      ...prev,
      [field]: value,
    }));
  }, []);

  const handleComplete = useCallback(() => {
    props.onComplete(profileData);
  }, [props, profileData]);

  return {
    currentStep,
    profileData,
    isNextDisabled,
    handleNext,
    handleBack,
    updateField,
    handleComplete,
  };
}

export default useComponent;


