import type { Props, HookReturn } from '/virtual/types';
// components/index.tsx — main component composing sub-components
import React from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

export function MainView(props: OnboardingWizardProps) {
  const [step, setStep] = React.useState(1);
  const [data, setData] = React.useState<ProfileData>(props.initialProfile as ProfileData || { name: '', email: '', avatar: '', role: '', emailNotifications: false, theme: 'light' });

  const updateField = (field: keyof ProfileData, value: any) => setData(prev => ({ ...prev, [field]: value }));
  const isNextDisabled = step === 1 && (!data.name || !data.email);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={3}>Onboarding</Heading>
          <Progress value={(step / 3) * 100} size="sm" />
          <Text variant="caption">Step {step} of 3</Text>
        </Stack>

        <Card padding="var(--ggui-spacing-4)">
          {step === 1 && <Text>Profile Form Placeholder</Text>}
          {step === 2 && <Text>Preferences Form Placeholder</Text>}
          {step === 3 && <Text>Summary Placeholder</Text>}
        </Card>

        <Row justify="between">
          <Button variant="ghost" disabled={step === 1} onClick={() => setStep(s => s - 1)}>Back</Button>
          <Button variant="primary" disabled={isNextDisabled} onClick={() => step < 3 ? setStep(s => s + 1) : props.onComplete(data)}>
            {step === 3 ? 'Complete Setup' : 'Next'}
          </Button>
        </Row>
      </Stack>
    </Container>
  );
}


